import java.io.IOException;
import java.net.HttpURLConnection;
import java.net.URL;

public class IoTDeviceManagerHttpClient {

    private static final String BASE_URL = "your_base_url";

    public String sendCommand(String deviceId, String command) throws IOException {
        String url = BASE_URL + "/devices/" + deviceId + "/commands";
        HttpURLConnection connection = (HttpURLConnection) new URL(url).openConnection();
        connection.setRequestMethod("POST");
        connection.setRequestProperty("Content-Type", "application/json");
        connection.getOutputStream().write(command.getBytes());
        return new String(connection.getInputStream().readAllBytes());
    }

    public String getData(String deviceId) throws IOException {
        String url = BASE_URL + "/devices/" + deviceId + "/data";
        HttpURLConnection connection = (HttpURLConnection) new URL(url).openConnection();
        connection.setRequestMethod("GET");
        return new String(connection.getInputStream().readAllBytes());
    }
}